import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicThreeElements() {
        // [1,2,3] k=4: valid subarrays are [1],[2],[3],[1,2] → count 4
        assertEquals(4L, new Solution().countSubarrays(new int[]{1, 2, 3}, 4));
    }

    @Test
    void uniformOnesKTwo() {
        // [1,1,1] k=2: [1]×3 + [1,1]×2 = 5 valid subarrays
        assertEquals(5L, new Solution().countSubarrays(new int[]{1, 1, 1}, 2));
    }

    @Test
    void emptyArray() {
        assertEquals(0L, new Solution().countSubarrays(new int[]{}, 10));
    }

    @Test
    void singleElementExceedsLimit() {
        // [5] k=3: 5 > 3, no valid subarray
        assertEquals(0L, new Solution().countSubarrays(new int[]{5}, 3));
    }

    @Test
    void singleElementMeetsLimit() {
        // [5] k=5: 5 <= 5, exactly one valid subarray
        assertEquals(1L, new Solution().countSubarrays(new int[]{5}, 5));
    }

    @Test
    void allZerosKZero() {
        // [0,0,0] k=0: all 6 subarrays of length 1,2,3 sum to 0
        assertEquals(6L, new Solution().countSubarrays(new int[]{0, 0, 0}, 0));
    }

    @Test
    void adversarialLargeValues() {
        // [10,1,1,1,10] k=3: from idx1: [1],[1,1],[1,1,1]=3; from idx2: [1],[1,1]=2; from idx3: [1]=1. total=6
        assertEquals(6L, new Solution().countSubarrays(new int[]{10, 1, 1, 1, 10}, 3));
    }
}
